   346→          maybeCx, fc, input, std::move(compiler.stencil()), initialStencilOut,
   347→          stencilsOut, gcOutput)) {
   348→    return false;
   349→  }
   350→
   351→  assertException.reset();
   352→  return true;
   353→}
